import { FastifyInstance } from 'fastify';

export async function protectedRoutes(fastify: FastifyInstance) {
  fastify.get('/admin/stats', async (req, reply) => {
    // Auth logic mixed into handler
    const token = req.headers.authorization?.replace('Bearer ', '');
    if (!token) return reply.code(401).send({ error: 'No token' });
    const user = await verifyToken(token);
    if (user.role !== 'admin') return reply.code(403).send({ error: 'Forbidden' });
    return { stats: await getAdminStats() };
  });
}

Code Good:
import { FastifyInstance } from 'fastify';

export async function responseHooks(fastify: FastifyInstance) {
  fastify.addHook('onSend', async (req, reply, payload) => {
    reply.header('X-Request-Id', req.id);
    reply.header('X-Response-Time', reply.elapsedTime.toFixed(2));
    return payload;
  });

  fastify.addHook('onError', async (req, reply, error) => {
    req.log.error({
      err: error,
      requestId: req.id,
      url: req.url,
      method: req.method,
    }, 'Request error occurred');
  });
}

